} catch (error) {
    const screenshot = await ScreenshotUtil.takeScreenshot(driver, `Fail_${tcId}`);
    await ExcelReport.addResult({
        id: tcId,
        module: platform.name,
        name: 'Login UI Check',
        status: 'FAIL',
        time: `${Date.now() - startTime}ms`,
        screenshot: screenshot,
        remarks: error.message
    });
    throw error;
}

